(function(){function setSummary(node,payload){if(!node)return;node.textContent=JSON.stringify(payload,null,2);}
function appendCheck(container,label,ok,detail){if(!container)return;var li=document.createElement('li');li.className=ok?'ok':'err';li.textContent=label+': '+(ok?'ok':'fail')+(detail?' ('+detail+')':'');container.appendChild(li);}
function initHealthCheck(){var summaryEl=document.getElementById('health-summary');var checksEl=document.getElementById('health-checks');if(!summaryEl||!checksEl)return;var startedAt=new Date().toISOString();var checks=[{label:'track-event function',url:'/api/track-event'},{label:'auth config',url:'/api/auth?action=config'},{label:'public config',url:'/api/public-config'}];Promise.all(checks.map(function(check){return fetch(check.url,{cache:'no-store'}).then(function(res){return res.json().catch(function(){return{};}).then(function(body){appendCheck(checksEl,check.label,res.ok,body.error||body.status||('http '+res.status));return{ok:res.ok,label:check.label};});}).catch(function(err){appendCheck(checksEl,check.label,false,err.message||'request_failed');return{ok:false,label:check.label};});})).then(function(results){var failed=results.filter(function(item){return!item.ok;}).map(function(item){return item.label;});setSummary(summaryEl,{status:failed.length?'degraded':'ok',service:'efi-site',checked_at:new Date().toISOString(),page_loaded_at:startedAt,checks_total:results.length,failed_checks:failed});});}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initHealthCheck);}else{initHealthCheck();}})();